            <div key={level} className="space-y-2">
              <h3 className="text-sm text-zinc-400">{Math.round(level * 100)}%</h3>
              <div className="bg-zinc-900 p-4 rounded-xl">
                <Waveform />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};
